from config import supabase
import bcrypt
def hash_pass(pwd):
    return bcrypt.hashpw(pwd.encode(),bcrypt.gensalt()).decode()
def check_pass(pwd,hashed):
    return bcrypt.checkpw(pwd.encode(),hashed.encode())

def check_user_login(email,password):
    response = supabase.table("users").select("*").eq("email",email).execute()
    if response.data:
        user = response.data[0]
        if(check_pass(password,user["password"])):
            return user 
        else:
            return 0
    else:
        return 0
        
def make_new_user(email,Name,password):
    response = supabase.table("users").select("*").eq("email",email).execute()
    if response.data:
        return 0
    else:
        password=hash_pass(password)
        data  = {
            "name":Name , 
            "email":email,
            "password":password
        }
        response = supabase.table("users").insert(data).execute()
        return response.data[0]

def social_login(user):
    data  = {
            "name":user.get('name') or user.get('username') or None, 
            "email":user.get('email'),
            "password":"None"
        }
    response = supabase.table("users").select("*").eq("email",data["email"]).execute()
    if response.data:
        print(response.data[0])
        print("existing user")
        return response.data[0]
    else:
        data["password"]=hash_pass(data["password"])
        user = supabase.table("users").insert(data).execute()
        print("new user")
        response =  supabase.table("users").select("*").eq("email",data["email"]).execute()
        return response.data[0]

def check_premium(email):
    response = supabase.table("users").update({"premium":True}).eq("email",email).execute()
    
